INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "カリン", 62, 1000001, 0.0, -416.5, 190805, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", "2025/01/31 12:00:00", 1, 3.414, 1);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "カリン", 62, 1000002, 0.0, -416.5, 190805, "ミッションをクリアして、\n報酬をゲットしましょう！", "2025/01/31 12:00:00", 1, 3.099, 2);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "カリン", 63, 1000003, 0.0, -416.5, 190805, "受け取ることができる\n報酬があるようです\n確認してみてください", "2025/01/31 12:00:00", 1, 2.801, 3);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 2, "2030/01/01 14:59:59", "カリン", 63, 1000004, 0.0, -416.5, 190805, "報酬がもらえますよ！\nチェックしてみてください", "2025/01/31 12:00:00", 1, 0.0, 4);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1, 2, "2030/01/01 14:59:59", "カリン", 64, 1000005, 0.0, -363.0, 190805, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", "2025/01/31 12:00:00", 1, 2.12, 5);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "カリン", 64, 1000006, 0.0, -363.0, 190805, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", "2025/01/31 12:00:00", 1, 1.68, 6);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1, 2, "2030/01/01 14:59:59", "カリン", 64, 1000007, 0.0, -363.0, 190805, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", "2025/01/31 12:00:00", 1, 2.33, 7);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (7, 3, "2030/01/01 14:59:59", "ラビリスタ", 61, 1020101, -6.0, -285.0, 133701, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", "2025/01/31 12:00:00", 10201, 5.18, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "クリスティーナ", 61, 1020102, -2.0, -285.0, 133901, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", "2025/01/31 12:00:00", 10201, 8.77, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1, 6, "2030/01/01 14:59:59", "ネネカ", 61, 1020103, 0.0, -285.0, 133801, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", "2025/01/31 12:00:00", 10201, 15.5, 301);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (5, 2, "2030/01/01 14:59:59", "ランファ", 61, 1020201, 0.0, -285.0, 134301, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", "2025/02/28 12:00:00", 10202, 9.061, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "チカ", 61, 1020202, 0.0, -285.0, 134401, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", "2025/02/28 12:00:00", 10202, 7.699, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "アオイ", 61, 1020301, 0.0, -285.0, 134601, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", "2025/03/31 12:00:00", 10203, 8.595, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "クローチェ", 61, 1020302, 0.0, -285.0, 134501, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", "2025/03/31 12:00:00", 10203, 7.758, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (6, 2, "2030/01/01 14:59:59", "ルイズマリー", 61, 1020401, 0.0, -285.0, 132302, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", "2025/04/30 12:00:00", 10204, 7.0, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "イロハ", 61, 1020402, 0.0, -285.0, 132402, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", "2025/04/30 12:00:00", 10204, 7.904, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 4, "2030/01/01 14:59:59", "ソノ", 61, 1020403, 0.0, -285.0, 132502, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", "2025/04/30 12:00:00", 10204, 8.487, 301);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "カノン", 61, 1020502, 0.0, -285.0, 134901, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", "2025/05/31 12:00:00", 10205, 8.763, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (3, 1, "2030/01/01 14:59:59", "ツムギ", 61, 1020503, 0.0, -285.0, 134801, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", "2025/05/31 12:00:00", 10205, 6.417, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (7, 3, "2030/01/01 14:59:59", "エリス", 61, 1020601, 0.0, -285.0, 135001, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", "2025/06/30 12:00:00", 10206, 10.335, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (4, 2, "2030/01/01 14:59:59", "シェフィ", 61, 1020602, 0.0, -285.0, 135101, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", "2025/06/30 12:00:00", 10206, 6.281, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "プレシア", 61, 1020603, 0.0, -285.0, 135201, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", "2025/06/30 12:00:00", 10206, 12.244, 301);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (8, 2, "2030/01/01 14:59:59", "クリア", 61, 1020701, 0.0, -285.0, 135301, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", "2025/07/31 12:00:00", 10207, 6.339, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (9, 7, "2030/01/01 14:59:59", "アネモネ", 61, 1020702, 0.0, -285.0, 135401, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", "2025/07/31 12:00:00", 10207, 8.184, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 9, "2030/01/01 14:59:59", "アイラ", 61, 1020801, 0.0, -285.0, 129101, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", "2025/08/31 12:00:00", 10208, 3.906, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "シナツ", 61, 1020802, 0.0, -285.0, 129201, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", "2025/08/31 12:00:00", 10208, 14.465, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (3, 4, "2030/01/01 14:59:59", "ヒヨリ", 61, 1020803, 0.0, -285.0, 100101, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", "2025/08/31 12:00:00", 10208, 8.662, 301);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (3, 1, "2030/01/01 14:59:59", "レイ", 61, 1020804, 0.0, -285.0, 100301, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", "2025/08/31 12:00:00", 10208, 10.915, 401);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (7, 1, "2030/01/01 14:59:59", "ユキノ", 61, 1020901, 0.0, -285.0, 135802, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", "2025/09/30 12:00:00", 10209, 6.042, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1, 4, "2030/01/01 14:59:59", "サツキ", 61, 1020902, 0.0, -285.0, 135903, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", "2025/09/30 12:00:00", 10209, 9.402, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1, 8, "2030/01/01 14:59:59", "ルルィ", 61, 1020903, 0.0, -285.0, 136902, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", "2025/09/30 12:00:00", 10209, 8.16, 301);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 3, "2030/01/01 14:59:59", "カスミ", 61, 1021001, 0.0, -285.0, 137401, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", "2025/10/31 12:00:00", 10210, 5.0, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1, 4, "2030/01/01 14:59:59", "アラクネ", 61, 1021002, 0.0, -285.0, 136001, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", "2025/10/31 12:00:00", 10210, 8.12, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 4, "2030/01/01 14:59:59", "ナーナ", 61, 1021003, 0.0, -285.0, 136202, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", "2025/10/31 12:00:00", 10210, 6.386, 301);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (4, 3, "2030/01/01 14:59:59", "ユイ", 61, 1021101, 0.0, -285.0, 136402, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", "2025/11/30 12:00:00", 10211, 7.438, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (5, 1, "2030/01/01 14:59:59", "ミソラ", 61, 1021102, 0.0, -285.0, 136302, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", "2025/11/30 12:00:00", 10211, 8.35, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "シズル", 61, 1021201, 0.0, -285.0, 136501, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", "2025/12/31 12:00:00", 10212, 5.0, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "リノ", 61, 1021202, 0.0, -285.0, 137902, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", "2025/12/31 12:00:00", 10212, 5.25, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "ラビリスタ", 61, 1021203, 0.0, -285.0, 106801, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", "2025/12/31 12:00:00", 10212, 7.5, 301);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "ライラエル", 61, 1021301, 0.0, -285.0, 126501, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", "2026/01/31 12:00:00", 10213, 8.204, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 1, "2030/01/01 14:59:59", "ネフィ＝ネラ", 61, 1021302, 0.0, -285.0, 129701, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", "2026/01/31 12:00:00", 10213, 7.176, 201);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (5, 1, "2030/01/01 14:59:59", "ヴァイオレット", 61, 1021303, 0.0, -285.0, 133101, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", "2026/01/31 12:00:00", 10213, 8.602, 301);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (3, 1, "2030/01/01 14:59:59", "ライラエル", 61, 1021304, 0.0, -285.0, 138101, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", "2026/02/06 12:00:00", 10213, 10.14, 102);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (7, 1, "2030/01/01 14:59:59", "ネフィ＝ネラ", 61, 1021305, 0.0, -285.0, 138201, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", "2026/02/06 12:00:00", 10213, 10.152, 202);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (3, 4, "2030/01/01 14:59:59", "ヴァイオレット", 61, 1021306, 0.0, -285.0, 138001, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", "2026/02/06 12:00:00", 10213, 9.688, 302);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (1, 2, "2030/01/01 14:59:59", "ペコリーヌ", 61, 1021307, 0.0, -285.0, 138301, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", "2026/02/12 12:00:00", 10213, 5.928, 401);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (2, 4, "2030/01/01 14:59:59", "ワカナ", 61, 1021401, 0.0, -285.0, 138702, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", "2026/02/28 12:00:00", 10214, 9.19, 101);
INSERT INTO `v1_a0dde6d08116f9322806a5bb986b23b3d14f0c581e0da3872c6d7166d052b5b3` VALUES (3, 1, "2030/01/01 14:59:59", "シオリ", 61, 1021402, 0.0, -285.0, 138802, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", "2026/02/28 12:00:00", 10214, 8.724, 201);
